import { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import axios from "../api/axios";

export default function PaymentPage() {
    const { bookingId } = useParams();
    const navigate = useNavigate();
    const [booking, setBooking] = useState(null);
    const [loading, setLoading] = useState(false);
    const [paymentMethod, setPaymentMethod] = useState("UPI");

    useEffect(() => {
        // Fetch booking details (optional, or pass via state)
        // For now, we'll trust the ID and just show a generic amount or fetch if needed.
        // Let's mock the amount for simplicity or fetch it.
        // Real implementation would fetch /api/bookings/:id
    }, [bookingId]);

    const handlePayment = async () => {
        setLoading(true);

        // Simulate Gateway Delay
        setTimeout(async () => {
            try {
                // Generate Mock Transaction ID
                const transactionId = "TXN" + Date.now() + Math.floor(Math.random() * 1000);
                const qrCodeData = `PARKSENSE:${bookingId}:${transactionId}:PAID`; // Simple data for QR

                await axios.post("/bookings/confirm-payment", {
                    bookingId,
                    paymentDetails: {
                        method: paymentMethod,
                        transactionId
                    },
                    qrCode: qrCodeData
                });

                setLoading(false);
                navigate(`/receipt/${bookingId}`);
            } catch (err) {
                console.error("Payment Failed", err);
                setLoading(false);
                alert("Payment Verification Failed");
            }
        }, 2000); // 2 second delay for realism
    };

    return (
        <div style={{ display: "flex", justifyContent: "center", alignItems: "center", minHeight: "80vh", background: "#f4f6f8" }}>
            <div style={{ background: "white", padding: "40px", borderRadius: "20px", boxShadow: "0 10px 30px rgba(0,0,0,0.1)", textAlign: "center", maxWidth: "400px", width: "100%" }}>
                <h2 style={{ color: "#2c3e50", marginBottom: "20px" }}>Secure Payment</h2>

                <div style={{ background: "#e8f5e9", padding: "15px", borderRadius: "10px", marginBottom: "20px", border: "1px dashed #2e7d32" }}>
                    <p style={{ margin: "0", color: "#2e7d32", fontWeight: "bold" }}>Booking ID: {bookingId.slice(-6).toUpperCase()}</p>
                    {/* Amount can be passed via location.state or fetched. We'll show a placeholder or handle it later. */}
                </div>

                <p style={{ textAlign: "left", marginBottom: "10px", fontWeight: "bold", color: "#555" }}>Choose Payment Method:</p>
                <div style={{ display: "flex", gap: "10px", marginBottom: "30px" }}>
                    <button
                        onClick={() => setPaymentMethod("UPI")}
                        style={{ ...methodStyle, background: paymentMethod === "UPI" ? "#e3f2fd" : "white", borderColor: paymentMethod === "UPI" ? "#2196f3" : "#ddd" }}
                    >
                        📱 UPI / QR
                    </button>
                    <button
                        onClick={() => setPaymentMethod("Card")}
                        style={{ ...methodStyle, background: paymentMethod === "Card" ? "#e3f2fd" : "white", borderColor: paymentMethod === "Card" ? "#2196f3" : "#ddd" }}
                    >
                        💳 Card
                    </button>
                </div>

                <button
                    onClick={handlePayment}
                    disabled={loading}
                    style={{
                        width: "100%", padding: "15px", borderRadius: "10px", border: "none",
                        background: loading ? "#ccc" : "#2ecc71", color: "white", fontSize: "18px", fontWeight: "bold", cursor: loading ? "not-allowed" : "pointer",
                        transition: "0.3s"
                    }}
                >
                    {loading ? "Processing..." : `Pay Now`}
                </button>

                <p style={{ marginTop: "20px", fontSize: "0.8em", color: "#95a5a6" }}>
                    🔒 256-bit Secure SSL Connection
                </p>
            </div>
        </div>
    );
}

const methodStyle = {
    flex: 1, padding: "10px", border: "2px solid", borderRadius: "10px", cursor: "pointer", fontWeight: "bold", color: "#555"
};
